/*顶栏*/
#top-bar {
    position: fixed;
    pointer-events: none;
    z-index: 99;
    background: none;
    border: 0;
    background-color: rgba(0, 0, 0, 0) !important;
    box-shadow: none;
    overflow: visible;
    width: auto;
    height: auto;
    left: 0;
    right: auto;
}

#top-bar::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: auto;
    bottom: auto;
    width: 100%;
    height: 100%;
    background-image: url('');
    background-size: auto;
    background-repeat: no-repeat;
    background-position: left top;
    border: 0px solid rgba(242, 239, 234, 0);
    border-radius: 0px;
    z-index: 999;
    filter: 
    contrast(1)      /* 对比度 */
    brightness(1)    /* 暗度*/
    saturate(1)      /* 饱和度 */
    hue-rotate(1deg)  /* 色相 */
}

@media screen and (max-width: 9999px) {
    #top-bar {
        width: 100vw;
        height: auto;
        overflow: visible !important;
    }

    #top-bar::before {
        min-width: 100%;
        min-height: 100px;
        background-size: contain;
        background-position: center top;
    }
}


/*顶栏小装饰*/
#top-bar::after {
    content: '';
    position: absolute;
    bottom: -60px; 
    left: 25%;
    transform: translateX(-50%);
    width: 200px; /* 装饰宽度 */
    height: 40px; /* 装饰高度 */
    background-image: url(''); 
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    z-index: 10000;
    pointer-events: none;
    filter: 
    contrast(1)      /* 对比度 */
    brightness(1)    /* 暗度*/
    saturate(1)      /* 饱和度 */
    hue-rotate(1deg)  /* 色相 */
}


