/* -1. 聊天气泡整体布局与间距- */
.mes {
  position: relative;
  z-index: 1;
  background-size: 100% auto; 
  background-attachment: local; 
  transition: transform 0.2s ease; 
  transform-origin: top center;
  max-width: 420px;/*💽气泡框大小*/
  margin: 210px auto 80px;/*💿次选调整第一个数值，气泡间缝大小*/
  transform: scale(1) rotate(0deg) !important;/*📼调scale括号内，加小数点1.1这样小调*/
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
  background-repeat: repeat-y;
  background-position: top center;
  overflow: visible;
  border: 0 !important;
  border-width: 0 !important;
  border-style: none !important;
  border-color: transparent !important;
  outline: 0 !important;
  box-shadow: none !important; 
  padding-bottom: 0px; 
    filter: 
    contrast(1)      /* 对比度 */
    brightness(1)    /* 暗度*/
    saturate(1)      /* 饱和度 */
    hue-rotate(1deg)  /* 色相 */
}


/* ========头像与头像框-没做头像默认隐藏========= */
/* 头像容器位置 */
.mesAvatarWrapper {
    position: absolute !important;
    top: -70px !important;    /* 💽上下微调 */
    left: 85px !important;   /* 💽左右微调 */
    width: auto !important;
    height: auto !important;
    padding: 0 !important;
    margin: 0 !important;
    z-index: 3 !important;
    overflow: visible !important;
    filter: none !important;
    box-shadow: none !important;
}

/* 头像本体 */
.mesAvatarWrapper .avatar {
    width: 100px;  
    height: 100px;
    transform: scale(2.5) rotate(0deg) !important; /* 💽缩放与旋转 */
    transform-origin: center center !important;
    max-width: unset !important;
    max-height: unset !important;
    -webkit-clip-path: polygon(7% 15%, 95% 15%, 95% 68%, 7% 68%);
    clip-path: polygon(7% 15%, 95% 15%, 95% 68%, 7% 68%);
}

.mesAvatarWrapper .avatar img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    box-shadow: none !important;
}

/* 头像框 */
.mesAvatarWrapper::after {
    content: '';
    position: absolute;
    top: 25% !important;   /* 💽锚点居中 */
    left: 50% !important;  /* 💽锚点居中 */
    width: 100% !important;
    height: 100% !important;
    transform: translate(-50%, -50%) scale(2.5) rotate(0deg) !important; 
    background-image: url('');
    background-size: contain !important;
    background-position: center center !important;
    background-repeat: no-repeat !important;
    pointer-events: none;
    z-index: 4;
    filter: 
    contrast(1)      /* 对比度 */
    brightness(1)    /* 暗度*/
    saturate(1)      /* 饱和度 */
    hue-rotate(1deg)  /* 色相 */
}

/* .2.名字与时间戳 */

/* 💽名字 */
.name_text {
    position: absolute !important;
    z-index: 9;
    top: -40px !important;      /* 💽上下微调 */
    left: 50% !important;       
    transform: translateX(-50%) !important; 
    width: auto !important;
    text-align: center !important; 
    font-size: 45px !important;
    font-weight: 300 !important;
    white-space: nowrap !important;
    color: #000 !important; /* 颜色 */
    opacity: 0.9;
    -webkit-text-stroke: 0px #ffffff !important;
    paint-order: stroke fill !important;
}

.name_text::before {
    content: ''; 
    display: inline-block;
    margin-right: -5px;
    color: inherit;
    pointer-events: none;
}

.name_text::after {
    content: ''; 
    display: inline-block;
    margin-left: 0px;
    pointer-events: none;
}


/* 💽时间戳 */
.timestamp {
    position: absolute !important;
    z-index: 9;
    top: 36px !important;     /* 💽上下微调 */
    left: 160px !important;    /* 💽左右微调 */
    font-size: 11px !important;
    font-weight: 500 !important;
    white-space: nowrap !important;
    color: #000 !important;
}

.timestamp::before {
    content: '';
    display: inline-block;
    margin-right: 0px;
}

.timestamp::after {
    content: '';
    display: inline-block;
    margin-left: 0px;
}

/* 3. 三元素信息 (楼层、计时、词符) */

/* 楼层数 */
.mesIDDisplay {
    position: absolute !important;
    z-index: 9;
    top: 106px !important;   /* 💽上下微调 */
    left: 25px !important;    /* 💽左右微调 */
    width: auto !important;
    margin: 0 !important;
    font-size: 11px !important;
    font-weight: 500 !important;
    color: #000 !important; 
    white-space: nowrap !important;
    display: inline-flex;
    align-items: center;
}

.mesIDDisplay::before {
    content: ''; 
    display: inline-block;
    margin-right: -5px;
}

.mesIDDisplay::after {
    content: ''; 
    display: inline-block;
    margin-left: 0px;
}

/* 回复计时 */
.mes_timer {
    position: absolute !important;
    z-index: 9;
    top: var(--element-top, 107px) !important; 
    left: var(--element-left, 240px) !important;
    transform: translateX(-50%) rotate(0deg);
    font-size: 11px !important;
    font-weight: 400 !important;
    color: #000 !important; 
    white-space: nowrap;
    cursor: default;
    opacity: 1;
}

.mes_timer::before {
    content: ''; 
    display: inline-block;
    margin-right: -2px;
}

.mes_timer::after {
    content: '';
    display: inline-block;
    margin-left: 0px;
}

/* 词符数 */
.tokenCounterDisplay {
    position: absolute !important;
    z-index: 9;
    top: -10px !important;     /* 💽上下微调 */
    left: 145px !important;    /* 💽左右微调 */
    transform: translateX(-50%) rotate(0deg);
    font-size: 10px !important;
    font-weight: 300 !important;
    color: #000 !important; 
    -webkit-text-stroke: 0.5px #ffffff !important; /* 描边优化 */
    paint-order: stroke fill !important;
    white-space: nowrap;
    opacity: 1;
}

.tokenCounterDisplay::before {
    content: '';
    display: inline-block;
    margin-right: 0px;
}

.tokenCounterDisplay::after {
    content: '';
    display: inline-block;
    margin-left: 0px;
}

/* 4. 操作按钮 (小铅笔、复制等 - 平时状态) */
.mes_buttons {
    position: absolute !important;
    z-index: 9;
    top: 60px !important;      /* 💽上下位置 */
    right: 40px !important;    /* 💽左右位置 */
    color: #000;
    display: flex !important;             
    flex-direction: row;       
    align-items: center;       
    gap: 0px;                  /* 间距*/
    margin: 0 !important;
    padding: 0 !important;
    opacity: 0;           
    transition: opacity 0.2s ease; 
}

.mes:hover .mes_buttons {
    opacity: 1;
}

.mes_buttons > div {
    margin: 0 !important;
    padding: 0 1px !important; 
}

.mes_buttons[style*="display: none"],
.mes_buttons[style*="display:none"] {
    display: none !important;
    opacity: 0 !important;
}


/* 编辑状态菜单 */
.mes_edit_buttons {
    position: absolute !important;
    z-index: 10;
    top: 60px !important;      
    right: 40px !important;
    flex-direction: row;
    align-items: center;
    gap: 0px;        
    opacity: 1 !important; 
    display: none; 
}



/* -5. 文本框主体 (Text)- */
/* --- User (用户) 文本框 --- */
.mes[is_user="true"] .mes_text {
    padding-top: 45px !important;    /* 💽加大数值=文字下移，减小=文字上移 */
    padding-bottom: 15px !important; /* 💽底部留白 */
    padding-left: 20px !important;   /* 💽左侧留白 */
    padding-right: 25px !important;  /* 💽右侧留白 */
    min-height: 120px !important;  
    text-align: justify; 
}

/* --- Char (角色) 文本框 --- */
.mes[is_user="false"] .mes_text {
    padding-top: 25px !important;    /* 💽加大数值=文字下移，减小=文字上移 */
    padding-bottom: 5px !important; /* 💽底部留白 */
    padding-left: 20px !important;   /* 💽左侧留白 */
    padding-right: 25px !important; /* 💽右侧留白 */
    min-height: 120px !important;
    text-align: justify;
}


/*杂七杂八的东西*/
.mesIDDisplay, .mes_timer, .tokenCounterDisplay, .name_text, .timestamp {
    position: absolute !important;
    z-index: 9; /* 保证在气泡上层 */
    width: auto !important;
    white-space: nowrap !important;
    pointer-events: none; /* 让鼠标可以穿透文字点到气泡 */
}



