/*加载齿轮*/
#load-spinner {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    background-size: contain !important;
    filter: 
    contrast(1)      /* 对比度 */
    brightness(0)    /* 暗度*/
    saturate(1)      /* 饱和度 */
    hue-rotate(1deg) !important;  /* 色相 */

    /* 取消旋转动画 - 核心修复 */
    animation: none !important;
    transform: none !important;  /* 强制归位 */
    transition: none !important; /* 取消过渡 */

    /* 移除原图标内容 */
    border: none !important;
    border-radius: 0 !important;

    /* 设置合适的尺寸 */
    width: 64px !important;
    height: 64px !important;

    /* 隐藏原旋转元素 */
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
}

/* 确保原旋转器内容被隐藏 */
#load-spinner > * {
    display: none !important;
}

/* 如果原spinner有伪元素旋转动画，也要取消 */
#load-spinner::before,
#load-spinner::after {
    display: none !important;
    animation: none !important;
}



/*--杂七杂八的东西x2--*/
/* 强制移除省略号和小铅笔图标的所有阴影效果 */
.fa-ellipsis-h::before,
.fa-ellipsis::before,
.fa-pencil-alt::before,
.fa-pencil::before,
.mes_buttons button,
.mes_edit_buttons button,
.mes_buttons button:hover,
.mes_edit_buttons button:hover {
    box-shadow: none !important;
    text-shadow: none !important;
    filter: drop-shadow(0 0 0 transparent) !important;
    -webkit-filter: drop-shadow(0 0 0 transparent) !important;
    outline: none !important;
    border: none !important;
    background-color: transparent !important;
}




/* 隐藏消息文本开头的所有br标签 */
.mes_text br:first-child,
.mes_text br:nth-child(2),
.mes_text br:nth-child(3) {
   display: none !important;
